// Load tasks, user preferences, heartbeat state, and recent memories
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const CHAT_ID = '{{TELEGRAM_CHAT_ID}}';
const http = this.helpers.httpRequest;

async function pgrest(path) {
  const res = await http({
    method: 'GET',
    url: `${SUPABASE_URL}${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  return typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
}

const userId = `telegram:${CHAT_ID}`;

// Load all context in parallel
const [tasks, profiles, heartbeatCfg, briefingCfg, recentMemory, soul] = await Promise.all([
  pgrest(`/rest/v1/tasks?user_id=eq.${encodeURIComponent(userId)}&status=in.(pending,in_progress)&order=due_date.asc.nullslast,priority.desc`),
  pgrest(`/rest/v1/user_profiles?user_id=eq.${encodeURIComponent(userId)}&select=display_name,timezone,preferences`),
  pgrest('/rest/v1/heartbeat_config?check_name=eq.heartbeat&select=config,last_run,enabled'),
  pgrest('/rest/v1/heartbeat_config?check_name=eq.morning_briefing&select=config,last_run,enabled'),
  pgrest('/rest/v1/memory_long?order=created_at.desc&limit=3&select=content,category'),
  pgrest('/rest/v1/soul?key=eq.name&select=content')
]);

const profile = (Array.isArray(profiles) && profiles.length > 0) ? profiles[0] : {};
const prefs = profile.preferences || {};
const tz = profile.timezone || 'Europe/Berlin';
const botName = (Array.isArray(soul) && soul.length > 0) ? soul[0].content : 'Assistant';

// Current time in user's timezone
const now = new Date();
const userTime = new Date(now.toLocaleString('en-US', { timeZone: tz }));
const currentHour = userTime.getHours();
const currentMinute = userTime.getMinutes();

// Heartbeat state
const hbEnabled = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0) ? heartbeatCfg[0].enabled : false;
const hbLastRun = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0 && heartbeatCfg[0].last_run) ? new Date(heartbeatCfg[0].last_run) : null;
const hbMinInterval = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0 && heartbeatCfg[0].config) ? (heartbeatCfg[0].config.min_interval_hours || 2) : 2;

// Morning briefing state
const mbEnabled = (Array.isArray(briefingCfg) && briefingCfg.length > 0) ? briefingCfg[0].enabled : false;
const mbLastRun = (Array.isArray(briefingCfg) && briefingCfg.length > 0 && briefingCfg[0].last_run) ? new Date(briefingCfg[0].last_run) : null;
const mbPrefs = prefs.morning_briefing || {};
const mbTime = mbPrefs.time || '08:00';
const [mbHour, mbMinute] = mbTime.split(':').map(Number);

// Categorize tasks
const overdue = (Array.isArray(tasks) ? tasks : []).filter(t => t.due_date && new Date(t.due_date) < now);
const dueToday = (Array.isArray(tasks) ? tasks : []).filter(t => {
  if (!t.due_date) return false;
  const d = new Date(t.due_date);
  return d.toDateString() === userTime.toDateString() && d >= now;
});
const urgent = (Array.isArray(tasks) ? tasks : []).filter(t => t.priority === 'urgent');

// Check if morning briefing should fire
let shouldBrief = false;
let briefingReason = '';
if (mbEnabled && mbPrefs.enabled) {
  const timeDiff = (currentHour * 60 + currentMinute) - (mbHour * 60 + mbMinute);
  const isInWindow = timeDiff >= 0 && timeDiff < 15;
  const alreadyBriefedToday = mbLastRun && mbLastRun.toDateString() === userTime.toDateString();
  const mbHoursSinceLastRun = mbLastRun ? (now.getTime() - mbLastRun.getTime()) / (1000 * 60 * 60) : 999;
  if (isInWindow && !alreadyBriefedToday && mbHoursSinceLastRun >= 1) {
    shouldBrief = true;
    briefingReason = 'morning_briefing';
  }
}

// Check if proactive message should fire (rate-limited)
let shouldProactive = false;
if (hbEnabled && !shouldBrief) {
  const hoursSinceLastRun = hbLastRun ? (now.getTime() - hbLastRun.getTime()) / (1000 * 60 * 60) : 999;
  if (hoursSinceLastRun >= hbMinInterval) {
    if (overdue.length > 0 || urgent.length > 0) {
      shouldProactive = true;
    }
  }
}

return [{ json: {
  hasAction: shouldBrief || shouldProactive,
  reason: shouldBrief ? briefingReason : (shouldProactive ? 'proactive' : 'none'),
  botName,
  userName: profile.display_name || 'User',
  timezone: tz,
  currentTime: userTime.toISOString(),
  tasks: Array.isArray(tasks) ? tasks : [],
  overdue: overdue.map(t => ({ id: t.id, title: t.title, priority: t.priority, due_date: t.due_date })),
  dueToday: dueToday.map(t => ({ id: t.id, title: t.title, priority: t.priority, due_date: t.due_date })),
  urgent: urgent.map(t => ({ id: t.id, title: t.title, due_date: t.due_date })),
  totalPending: Array.isArray(tasks) ? tasks.length : 0,
  recentMemory: Array.isArray(recentMemory) ? recentMemory.map(m => m.content) : [],
  isMorningBriefing: shouldBrief,
  language: prefs.language || 'English'
}}];

// Call Claude Haiku to compose a proactive message (or SKIP)
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const http = this.helpers.httpRequest;

// Get Anthropic API key from DB
const cfgResp = await http({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/tools_config?tool_name=eq.anthropic&select=config`,
  headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' }
});
const apiKey = (Array.isArray(cfgResp) && cfgResp.length > 0) ? cfgResp[0].config.api_key : null;
if (!apiKey) return [{ json: { message: 'SKIP', error: 'No Anthropic API key configured' } }];

const ctx = $input.first().json;

let systemPrompt;
const lang = ctx.language || 'English';
if (ctx.isMorningBriefing) {
  systemPrompt = `You are ${ctx.botName}, a personal assistant. Compose a morning briefing for ${ctx.userName}. Include: a friendly greeting, today's tasks (if any), overdue tasks (if any), and a motivating note. Keep it SHORT (3-5 sentences). Use a natural, warm tone. Respond in ${lang}. Current time: ${ctx.currentTime} (${ctx.timezone}).`;
} else {
  systemPrompt = `You are ${ctx.botName}, a personal assistant. You are proactively checking in with ${ctx.userName}. There are overdue or urgent tasks that need attention. Compose a SHORT reminder (1-3 sentences). Be helpful, not annoying. If nothing seems worth messaging about, respond with exactly the word SKIP and nothing else. Respond in ${lang}. Current time: ${ctx.currentTime} (${ctx.timezone}).`;
}

let userMsg = '';
if (ctx.overdue.length > 0) userMsg += `Overdue tasks:\n${ctx.overdue.map(t => `- ${t.title} (due: ${t.due_date}, priority: ${t.priority})`).join('\n')}\n\n`;
if (ctx.dueToday.length > 0) userMsg += `Due today:\n${ctx.dueToday.map(t => `- ${t.title} (priority: ${t.priority})`).join('\n')}\n\n`;
if (ctx.urgent.length > 0) userMsg += `Urgent:\n${ctx.urgent.map(t => `- ${t.title}`).join('\n')}\n\n`;
userMsg += `Total pending tasks: ${ctx.totalPending}\n`;
if (ctx.recentMemory.length > 0) userMsg += `\nRecent context:\n${ctx.recentMemory.join('\n')}`;

const response = await http({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 512,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMsg }]
  }
});

const message = (response.content && response.content[0]) ? response.content[0].text : 'SKIP';
return [{ json: { message, reason: ctx.reason, isMorningBriefing: ctx.isMorningBriefing } }];

// Update heartbeat_config last_run
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const http = this.helpers.httpRequest;

const reason = $input.first().json.reason || 'proactive';
const checkName = reason === 'morning_briefing' ? 'morning_briefing' : 'heartbeat';

await http({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/heartbeat_config?check_name=eq.${checkName}`,
  headers: {
    'apikey': SUPABASE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: { last_run: new Date().toISOString() }
});

return [{ json: { status: 'sent', check_name: checkName, timestamp: new Date().toISOString() } }];
